def calculate_total(items):
    total = 0.0
    for item in items:
        total += item.get('price', 0.0)
    return total

def process_order(order_id, items):
    total = calculate_total(items)
    result = {
        'order_id': order_id,
        'total': total,
        'status': 'processed'
    }
    return result

def validate_item(item):
    if 'name' not in item or 'price' not in item:
        return False
    if not isinstance(item['name'], str) or not isinstance(item['price'], (int, float)):
        return False
    return True

from app.services import process_order

if __name__ == '__main__':
    test_items = [
        {'name': 'Item 1', 'price': 10.0},
        {'name': 'Item 2', 'price': 20.0}
    ]

    result = process_order('ORD-001', test_items)
    print(f"Order result: {result}")

    invalid_items = [
        {'name': 'Item 3', 'price': 'invalid'}
    ]

    process_order('ORD-002', invalid_items)

